def subset_sum(xs, target):
    """
    Returns True if some subset of nonnegative integers xs sums to target.
    """
    if target < 0:
        return False
    reachable = {0}
    for num in xs:
        # Optimization: if num is 0, no change, skip?
        # But keep it simple; adding 0 doesn't change reachable.
        new_sums = {s + num for s in reachable}
        reachable |= new_sums
        if target in reachable:
            return True
    return target in reachable
